// Some portions generated by Claude
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNull;
import static org.junit.jupiter.api.Assertions.assertTrue;
import static org.junit.jupiter.api.Assertions.fail;

import java.lang.ref.WeakReference;
import java.lang.reflect.InvocationTargetException;
import java.util.concurrent.TimeUnit;

import org.codehaus.commons.compiler.CompileException;
import org.codehaus.janino.SimpleCompiler;
import org.junit.jupiter.api.Test;

/**
 * Milestone-0 feasibility spike for the Janino whole-stage codegen plan
 * (plans/lmdb-native-engine/17-janino-whole-stage-codegen.md). Pins four facts the M2 infrastructure design depends on:
 * (a) Janino compiles and runs a kernel implementing a public engine-side interface on the current JDK; (b)
 * package-private access from generated code into this package does NOT work across the Janino child classloader
 * boundary, so the codegen SPI surface must be public; (c) compile latency for a representative ~200-line kernel is
 * bounded; (d) generated classes are collectible once the kernel instance and loader are dropped.
 */
public class LmdbNativeJaninoSpikeTest {

	/** Public on purpose: generated classes live in a child classloader and can only see public engine surface. */
	public interface SpikeKernel {
		long sum(long[] values, int count);
	}

	private static Class<?> compile(String className, String source) throws Exception {
		SimpleCompiler compiler = new SimpleCompiler();
		compiler.setParentClassLoader(LmdbNativeJaninoSpikeTest.class.getClassLoader());
		compiler.cook(source);
		return compiler.getClassLoader().loadClass(className);
	}

	@Test
	public void compilesAndRunsKernelAgainstPublicInterface() throws Exception {
		String source = "package org.eclipse.rdf4j.sail.lmdb.gen;\n"
				+ "public final class SpikeKernelImpl\n"
				+ "        implements org.eclipse.rdf4j.sail.lmdb.evaluation.LmdbNativeJaninoSpikeTest.SpikeKernel {\n"
				+ "    public long sum(long[] values, int count) {\n"
				+ "        long total = 0L;\n"
				+ "        for (int i = 0; i < count; i++) {\n"
				+ "            total += values[i];\n"
				+ "        }\n"
				+ "        return total;\n"
				+ "    }\n"
				+ "}\n";
		Class<?> kernelClass = compile("org.eclipse.rdf4j.sail.lmdb.gen.SpikeKernelImpl", source);
		SpikeKernel kernel = (SpikeKernel) kernelClass.getDeclaredConstructor().newInstance();
		long[] values = { 1L, 2L, 3L, Long.MIN_VALUE };
		assertEquals(6L + Long.MIN_VALUE, kernel.sum(values, 4));
	}

	@Test
	public void packagePrivateAccessAcrossClassLoadersDoesNotWork() throws Exception {
		// Same package NAME as the engine, but a different classloader => different runtime package. Accessing the
		// package-private LmdbNativeSpecialization must fail either at Janino compile time or with IllegalAccessError
		// at run time; the design consequence (a public codegen SPI) is the same either way.
		String source = "package org.eclipse.rdf4j.sail.lmdb.evaluation;\n"
				+ "public final class SneakyAccess {\n"
				+ "    public static boolean go() {\n"
				+ "        return LmdbNativeSpecialization.enabled();\n"
				+ "    }\n"
				+ "}\n";
		try {
			Class<?> sneaky = compile("org.eclipse.rdf4j.sail.lmdb.evaluation.SneakyAccess", source);
			sneaky.getMethod("go").invoke(null);
			fail("package-private access across classloaders unexpectedly succeeded; "
					+ "the M2 public-SPI design decision would need revisiting");
		} catch (CompileException expected) {
			// Janino refused at compile time: acceptable outcome.
		} catch (InvocationTargetException expected) {
			assertTrue(expected.getCause() instanceof IllegalAccessError,
					"expected IllegalAccessError, got " + expected.getCause());
		}
	}

	@Test
	public void compileLatencyForRepresentativeKernelIsBounded() throws Exception {
		// Warm the compiler once so the measured number reflects steady-state compiles, not Janino classloading.
		compile("org.eclipse.rdf4j.sail.lmdb.gen.Warm",
				"package org.eclipse.rdf4j.sail.lmdb.gen; public final class Warm { public int id(int x) { return x; } }");

		String source = representativeKernelSource();
		long start = System.nanoTime();
		Class<?> kernelClass = compile("org.eclipse.rdf4j.sail.lmdb.gen.RepresentativeKernel", source);
		long elapsedMillis = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start);

		SpikeKernel kernel = (SpikeKernel) kernelClass.getDeclaredConstructor().newInstance();
		long[] values = new long[64];
		for (int i = 0; i < values.length; i++) {
			values[i] = i;
		}
		assertEquals(2016L, kernel.sum(values, values.length));

		System.out.println("[janino-spike] representative kernel (" + source.lines().count() + " lines) compiled in "
				+ elapsedMillis + " ms");
		assertTrue(elapsedMillis < 10_000L, "compile took " + elapsedMillis + " ms");
	}

	@Test
	public void generatedClassesAreCollectibleOnceDropped() throws Exception {
		SimpleCompiler compiler = new SimpleCompiler();
		compiler.setParentClassLoader(LmdbNativeJaninoSpikeTest.class.getClassLoader());
		compiler.cook("package org.eclipse.rdf4j.sail.lmdb.gen; public final class Ephemeral { }");
		Class<?> ephemeral = compiler.getClassLoader().loadClass("org.eclipse.rdf4j.sail.lmdb.gen.Ephemeral");
		WeakReference<ClassLoader> loaderRef = new WeakReference<>(ephemeral.getClassLoader());
		compiler = null;
		ephemeral = null;

		long deadline = System.nanoTime() + TimeUnit.SECONDS.toNanos(10);
		while (loaderRef.get() != null && System.nanoTime() < deadline) {
			System.gc();
			Thread.sleep(50);
		}
		assertNull(loaderRef.get(), "generated classloader was not collected within 10s");
	}

	private static String representativeKernelSource() {
		// Roughly the shape and size of a fused pipeline kernel: an entry loop plus a spread of small helper
		// methods, conservative Java only (explicit loops, primitives, no modern syntax).
		StringBuilder source = new StringBuilder();
		source.append("package org.eclipse.rdf4j.sail.lmdb.gen;\n")
				.append("public final class RepresentativeKernel\n")
				.append("        implements org.eclipse.rdf4j.sail.lmdb.evaluation.LmdbNativeJaninoSpikeTest.SpikeKernel {\n")
				.append("    public long sum(long[] values, int count) {\n")
				.append("        long total = 0L;\n")
				.append("        for (int i = 0; i < count; i++) {\n")
				.append("            total += stage0(values[i]);\n")
				.append("        }\n")
				.append("        return total;\n")
				.append("    }\n");
		for (int stage = 0; stage < 24; stage++) {
			source.append("    private long stage")
					.append(stage)
					.append("(long value) {\n")
					.append("        long result = value;\n")
					.append("        if (result < 0L) {\n")
					.append("            result = -result;\n")
					.append("        }\n");
			if (stage < 23) {
				source.append("        return stage").append(stage + 1).append("(result) - result + value;\n");
			} else {
				source.append("        return value;\n");
			}
			source.append("    }\n");
		}
		source.append("}\n");
		return source.toString();
	}
}
